SELECT search_term
FROM document_search
WHERE doc_type_id = '1';

SELECT COUNT(search_results) AS search_result_count
FROM document_search
WHERE search_term = 'Search Term 2';

SELECT attr_name
FROM attributes
WHERE active_ind = 'Y';

SELECT doc_type_id, search_term
FROM document_search
WHERE search_id = 1;

SELECT doc_type_name, description
FROM document_types
ORDER BY doc_type_name;

SELECT COUNT(*) AS total_active_attributes
FROM attributes
WHERE active_ind = 'Y';
